"use strict";

var curry = require("./curry.js");

var go = require("./go.js");

var reduce = require("./reduce.js");

var not = require("./not.js");

var mapL = require("../Lazy/mapL.js");

var takeUntilL = require("../Lazy/takeUntilL.js");

module.exports = curry(function every(f, iter) {
  return go(mapL(f, iter), takeUntilL(not), reduce(function (a, b) {
    return a && b;
  }), function () {
    var a = arguments.length > 0 && arguments[0] !== undefined ? arguments[0] : false;
    return a;
  }, Boolean);
});