"use strict";

var filterL = require("./filterL.js");

var curry = require("../Strict/curry.js");

var go1 = require("../Strict/go1.js");

var not = require("../Strict/not.js");

module.exports = curry(function rejectL(f, iter) {
  return filterL(function (a) {
    return go1(f(a), not);
  }, iter);
});